#r "nuget: MSBuild.StructuredLogger, 2.2.405"

using Microsoft.Build.Logging.StructuredLogger;

var build = BinaryLog.ReadBuild("build.binlog");
var projects = build.FindChildrenRecursive<Project>();

Console.WriteLine("=== ALL PROJECTS & STATUS ===");
foreach (var p in projects)
{
    var errs = p.FindChildrenRecursive<Error>().Count;
    Console.WriteLine($"  {p.Name} [{p.TargetFramework}] - Errors: {errs}");
}

Console.WriteLine("\n=== PROJECT REFERENCES (from evaluations) ===");
var items = build.FindChildrenRecursive<AddItem>().Where(i => i.Name == "ProjectReference");
foreach (var item in items)
{
    var proj = item.GetNearestParent<Project>();
    Console.WriteLine($"  {proj?.Name} references:");
    foreach (var child in item.Children)
    {
        Console.WriteLine($"    -> {child}");
    }
}

Console.WriteLine("\n=== PACKAGE REFERENCES in Services.csproj ===");
var svcProj = projects.FirstOrDefault(p => p.Name == "Services.csproj");
if (svcProj != null)
{
    var pkgRefs = svcProj.FindChildrenRecursive<AddItem>().Where(i => i.Name == "PackageReference");
    foreach (var pr in pkgRefs)
    {
        foreach (var child in pr.Children)
            Console.WriteLine($"  {child}");
    }
}
EOF
